import{_ as n,o as i,c as r,ag as t}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Teamverwaltung","description":"","frontmatter":{},"headers":[],"relativePath":"de/settings/team.md","filePath":"de/settings/team.md"}'),l={name:"de/settings/team.md"};function a(s,e,h,g,u,o){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="teamverwaltung" tabindex="-1">Teamverwaltung <a class="header-anchor" href="#teamverwaltung" aria-label="Permalink to &quot;Teamverwaltung&quot;">​</a></h1><p>Laden Sie Teammitglieder ein, weisen Sie Rollen zu und kontrollieren Sie, wer auf was in Ihrem Arbeitsbereich zugreifen kann.</p><h2 id="teammitglieder-einladen" tabindex="-1">Teammitglieder einladen <a class="header-anchor" href="#teammitglieder-einladen" aria-label="Permalink to &quot;Teammitglieder einladen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Team</strong> oder <strong>Unternehmen &gt; Teammitglieder</strong></li><li>Klicken Sie auf <strong>Mitglied einladen</strong></li><li>Geben Sie die <strong>E-Mail-Adresse</strong> der Person ein</li><li>Wählen Sie eine <strong>Rolle</strong> (siehe unten)</li><li>Klicken Sie auf <strong>Einladung senden</strong></li></ol><p>Der Eingeladene erhält eine E-Mail mit einem Link, um Ihrem Arbeitsbereich beizutreten. Wenn er kein MyCompanyDesk-Konto hat, kann er während des Prozesses eines erstellen.</p><h2 id="rollen" tabindex="-1">Rollen <a class="header-anchor" href="#rollen" aria-label="Permalink to &quot;Rollen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rolle</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Vollständiger Zugriff auf alles, einschließlich Team- und Abrechnungsverwaltung</td></tr><tr><td><strong>Mitglied</strong></td><td>Zugriff auf zugewiesene Funktionen, kann Team oder Abrechnung nicht verwalten</td></tr><tr><td><strong>Buchhalter</strong></td><td>Nur-Lese-Zugriff mit spezifischen Buchhaltungsansichten</td></tr></tbody></table><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><p>Admins können:</p><ul><li>Teammitglieder verwalten (einladen, entfernen, Rollen ändern)</li><li>Auf Abrechnungs- und Abonnementeinstellungen zugreifen</li><li>Unternehmenseinstellungen konfigurieren</li><li>Auf alle Funktionen zugreifen</li></ul><h3 id="mitglied" tabindex="-1">Mitglied <a class="header-anchor" href="#mitglied" aria-label="Permalink to &quot;Mitglied&quot;">​</a></h3><p>Mitglieder haben Zugriff auf die Funktionen, die Sie ihnen zuweisen. Konfigurieren Sie ihre Berechtigungen pro Funktion.</p><h3 id="buchhalter" tabindex="-1">Buchhalter <a class="header-anchor" href="#buchhalter" aria-label="Permalink to &quot;Buchhalter&quot;">​</a></h3><p>Eine spezielle Rolle für externe Buchhalter:</p><ul><li>Finanzdaten einsehen (Rechnungen, Ausgaben, Berichte)</li><li>Kann standardmäßig keine Datensätze erstellen oder ändern</li><li>Spezifischer Berechtigungssatz für Prüfungszwecke</li></ul><h2 id="berechtigungen" tabindex="-1">Berechtigungen <a class="header-anchor" href="#berechtigungen" aria-label="Permalink to &quot;Berechtigungen&quot;">​</a></h2><p>Feinabgestimmte Berechtigungen ermöglichen die Zugriffskontrolle pro Funktion:</p><h3 id="seitenzugriff" tabindex="-1">Seitenzugriff <a class="header-anchor" href="#seitenzugriff" aria-label="Permalink to &quot;Seitenzugriff&quot;">​</a></h3><p>Wählen Sie, welche Bereiche jedes Mitglied sehen kann:</p><ul><li>Rechnungen</li><li>Angebote</li><li>Ausgaben</li><li>Kunden</li><li>Projekte</li><li>Verträge</li><li>Objekte</li><li>Zeiterfassung</li><li>Berichte</li><li>USt.</li><li>Einstellungen</li></ul><h3 id="bearbeitungsberechtigungen" tabindex="-1">Bearbeitungsberechtigungen <a class="header-anchor" href="#bearbeitungsberechtigungen" aria-label="Permalink to &quot;Bearbeitungsberechtigungen&quot;">​</a></h3><p>Für jede zugängliche Seite wählen Sie, ob das Mitglied:</p><ul><li><strong>Nur anzeigen</strong> — Lesezugriff, keine Änderungen</li><li><strong>Bearbeiten</strong> — Vollständiger Lese-/Schreibzugriff</li></ul><h2 id="buchhalter-kontakte" tabindex="-1">Buchhalter-Kontakte <a class="header-anchor" href="#buchhalter-kontakte" aria-label="Permalink to &quot;Buchhalter-Kontakte&quot;">​</a></h2><p>Verwalten Sie externe Buchhalter-Beziehungen:</p><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Team &gt; Buchhalter</strong></li><li>Klicken Sie auf <strong>Buchhalter hinzufügen</strong></li><li>Geben Sie Name und E-Mail ein</li><li>Klicken Sie auf <strong>Einladen</strong>, um den Zugang zu senden</li><li>Konfigurieren Sie die spezifischen Berechtigungen</li></ol><h3 id="buchhalter-zugang-verwalten" tabindex="-1">Buchhalter-Zugang verwalten <a class="header-anchor" href="#buchhalter-zugang-verwalten" aria-label="Permalink to &quot;Buchhalter-Zugang verwalten&quot;">​</a></h3><ul><li><strong>Einladen</strong> — Zugriffseinladung senden oder erneut senden</li><li><strong>Widerrufen</strong> — Zugang entfernen (kann später wiederhergestellt werden)</li><li><strong>Wiederherstellen</strong> — Zuvor widerrufenen Zugang reaktivieren</li><li><strong>Berechtigungen aktualisieren</strong> — Ändern, was sie sehen können</li></ul><h2 id="arbeitsbereiche-wechseln" tabindex="-1">Arbeitsbereiche wechseln <a class="header-anchor" href="#arbeitsbereiche-wechseln" aria-label="Permalink to &quot;Arbeitsbereiche wechseln&quot;">​</a></h2><p>Wenn Sie Mitglied mehrerer Arbeitsbereiche (Unternehmen) sind, wechseln Sie zwischen ihnen:</p><ol><li>Klicken Sie auf Ihr Kontomenü</li><li>Wählen Sie <strong>Arbeitsbereich wechseln</strong></li><li>Wählen Sie den Arbeitsbereich</li></ol><p>Oder erstellen Sie einen <strong>neuen Arbeitsbereich</strong> über dasselbe Menü.</p><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Verwenden Sie die Buchhalter-Rolle für Ihren Steuerberater — sie bietet genau den Zugang, den er benötigt</li><li>Legen Sie Mitgliederberechtigungen sorgfältig fest — nicht jeder braucht Zugriff auf Abrechnungs- oder Teameinstellungen</li><li>Überprüfen Sie den Teamzugang regelmäßig, besonders wenn Teammitglieder ihre Rollen wechseln</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Teamverwaltung über 1 Mitglied hinaus erfordert den <strong>Pro</strong>-Tarif. Unbegrenzte Mitglieder sind im <strong>Business</strong>-Tarif verfügbar.</p></div>',35)])])}const b=n(l,[["render",a]]);export{c as __pageData,b as default};
